<?php
namespace App\Filament\Resources; use App\Filament\Resources\SiteTourResource\Pages; use App\Modules\SiteTour\Models\SiteTour; use App\Filament\Support\AdminUploads; use Filament\Forms; use Filament\Forms\Form; use Filament\Resources\Resource; use Filament\Tables; use Filament\Tables\Table;
class SiteTourResource extends Resource { protected static ?string $model=SiteTour::class; protected static ?string $navigationIcon='heroicon-o-map'; protected static ?string $navigationGroup='Hoạt động bán hàng'; protected static ?string $modelLabel='Site tour'; protected static ?string $pluralModelLabel='Site tour'; public static function form(Form $form): Form { return $form->schema([Forms\Components\Select::make('user_id')->label('Nhân viên')->relationship('user','name')->searchable()->preload()->required(), Forms\Components\Select::make('project_id')->label('Khu đất')->relationship('project','name')->searchable()->preload()->required(), Forms\Components\TextInput::make('unit_code')->label('Mã căn/lô')->required(), Forms\Components\TextInput::make('customer_name')->label('Tên khách')->required(), Forms\Components\TextInput::make('latitude')->label('Vĩ độ')->numeric(), Forms\Components\TextInput::make('longitude')->label('Kinh độ')->numeric(), AdminUploads::image('image_path', 'Minh chứng', 'admin/site-tours')->columnSpanFull()])->columns(2); } public static function table(Table $table): Table { return $table->columns([Tables\Columns\TextColumn::make('user.name')->label('Nhân viên'), Tables\Columns\TextColumn::make('project.name')->label('Khu đất'), Tables\Columns\TextColumn::make('unit_code')->label('Mã căn/lô'), Tables\Columns\TextColumn::make('customer_name')->label('Khách'), Tables\Columns\TextColumn::make('created_at')->label('Thời gian')->dateTime('d/m/Y H:i')])->actions([Tables\Actions\EditAction::make(),Tables\Actions\DeleteAction::make()]); } public static function getPages(): array { return ['index'=>Pages\ListSiteTours::route('/'),'create'=>Pages\CreateSiteTour::route('/create'),'edit'=>Pages\EditSiteTour::route('/{record}/edit')]; } }
